def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 75 + np.log1p(cap) * 30 + np.exp(-usage)
        fluctuation = 0.0
        mod_factor = int((cap * 1000) % 31)
        if usage > 5:
            base_priority += 10000 * np.power(usage, 1.3) - 500 * np.sqrt(cap)
            if cap > 15:
                base_priority += 150 * np.cbrt(cap) + 50 * np.cos(cap * 2)
            else:
                base_priority -= 60 * usage + 100 * np.sin(cap * 5)
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.7) * 25 / i
            for r in range(3):
                base_priority += np.sum(np.random.RandomState(seed=idx+r).uniform(-5, 5, 5))
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2800 * delta ** 2 + 300 * (1 - np.sqrt(delta))
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.5)) * 30 / j
            if int(cap * 4) % 5 == 0:
                base_priority += 60 * np.tan(cap / 10)
                for x in range(2, 5):
                    fluctuation += np.sin(usage * np.pi * x * 0.9) * 10 / (x + 1)
        elif 3 < usage <= 4:
            base_priority += 1900 * (usage - 3) ** 1.7
            for k in range(1, 14):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 12 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 3)
                    if k == 10 and usage > 3.5:
                        fluctuation += 30
            if cap % 3.1 < 0.7:
                base_priority += 45 * np.sin(cap * 4)
        elif 2 < usage <= 3:
            base_priority += 1400 * (usage - 2) ** 2.2
            for m in range(1, 17):
                pwr = usage ** m
                if pwr < 0.7:
                    fluctuation += pwr * 28 / m
                    if m % 6 == 2:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 2)
                    if m == 13 and usage > 2.6:
                        fluctuation += 25
            if cap % 1.9 < 0.6:
                base_priority += 40 * np.cos(cap * 3.5)
        elif 1 < usage <= 2:
            base_priority += 1100 * (usage - 1) ** 3.5
            for n in range(1, 18):
                pwr = usage ** n
                if pwr < 0.55:
                    fluctuation += pwr * 30 / n
                    if n % 4 == 3:
                        fluctuation -= 5 * n
                else:
                    fluctuation += (1 - pwr) * 18 / (n + 1)
                    if n == 15 and usage > 1.8:
                        fluctuation += 20
            if cap % 1.3 < 0.4:
                base_priority += 32 * np.sin(cap * 2.5)
        elif 0.4 < usage <= 1:
            base_priority += 160 * (1 - usage) ** 1.5
            for o in range(1, 16):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.4) * 15 / o
                if usage < 0.05 * o:
                    fluctuation -= 10 * o
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 320
            elif cap < 1.0:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 4.5) * 25
        else:
            base_priority += 320 * (1 - usage) ** 2.5
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.2) * 16 / p
                if usage < 0.01 * p:
                    fluctuation -= 14 * p
            if cap < 0.01:
                base_priority += np.sqrt(cap) * 340
            elif cap < 1.1:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 7) * 35
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 120
            if usage > 0.7:
                priority += 130
            elif usage < 0.1:
                priority -= 70
                for q in range(1, 9):
                    priority -= q * np.exp(-usage * 25)
        elif cap < 1.2:
            priority += 55
            if usage > 0.8:
                priority += 75
            elif usage < 0.25:
                priority -= 40
            for s in range(1, 8):
                if int(cap * 1500) % (s + 5) == mod_factor % (s + 5):
                    priority += s * 8
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 55
                for t in range(1, 9):
                    priority -= t * 6
            elif usage > 0.9:
                priority += 110
                for u in range(1, 6):
                    priority += u * 14
            else:
                priority += 35
        proximity = 0
        if int(cap * 3000) % 23 == 0:
            proximity += 17
        if int(cap * 1100) % 29 == 0:
            proximity -= 14
        if int(cap * 200) % 11 == 0:
            proximity += 15
        for w in range(1, 11):
            diff = abs(usage - w / 11)
            if diff < 0.018:
                proximity += 23 / w
            elif diff < 0.04:
                proximity += 13 / w
            else:
                proximity -= 5 / w
        for x in range(1, 9):
            mod_chk = int(cap * 1800) % (x + 11)
            if mod_chk == mod_factor % (x + 11):
                proximity += x * 7
            elif mod_chk == 4:
                proximity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1800) % (y + 8)
            if mod_chk == 0:
                proximity += 12 * y
            elif mod_chk == 4:
                proximity -= 9 * y
        priority += proximity
        if usage < 0.003:
            for z in range(1, 10):
                priority -= z * 12
        elif usage > 0.97:
            for aa in range(1, 8):
                priority += aa * 14
        if cap > 3.0:
            if cap % 1.2 < 0.08:
                priority += 55
            if (int(cap * 3000) % 29 == 0) and (usage > 0.75):
                priority += 70
            for bb in range(1, 8):
                if (int(cap * 800) % (bb + 11) == 3) and (usage < 0.9):
                    priority -= 35
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
